// Entradas desde el vertex shader
in vec3 v_world_pos;
in vec3 v_world_normal;
in vec3 v_color;

// Uniform de iluminacion
uniform vec3 u_light_dir;   // direccion de la luz (hacia la fuente)
uniform vec3 u_light_color; // color de la luz
uniform vec3 u_ambient;     // termino ambiente

out vec4 frag_color;

