#version 330 core

// Atributos de entrada (un vertice por esquina)
in vec3 position;
in vec3 normal;
in vec3 color;
in vec2 texcoord;

// Uniforms de transformacion
uniform mat4 u_model;       // transformacion local -> mundo
uniform mat4 u_view;        // mundo -> camara
uniform mat4 u_projection;  // camara -> clip
uniform mat4 u_normal_mat;  // matriz modelo (o su inversa-transpuesta) para transformar normales

// Salidas hacia el fragment shader
out vec3 v_world_pos;
out vec3 v_world_normal;
out vec3 v_color;
out vec2 v_texcoord;

void main() {
    vec4 world_pos = u_model * vec4(position, 1.0);
    v_world_pos = world_pos.xyz;
    // Extraemos la parte 3x3 de la matriz (sin traslacion) para la normal
    mat3 n3 = mat3(u_normal_mat);
    v_world_normal = normalize(n3 * normal);
    v_color = color;
    v_texcoord = texcoord;

    gl_Position = u_projection * u_view * world_pos;
}

#version 330 core

// Entradas desde el vertex shader
in vec3 v_world_pos;
in vec3 v_world_normal;
in vec3 v_color;
in vec2 v_texcoord;

// Uniforms de iluminacion: dos luces direccionales (la primera es
// la luz principal del escenario, la segunda es una luz decorativa
// de color diferente) y una tercera luz tipo puntual que se activa
// cuando la pelota golpea alguno de los elementos del tablero.
uniform vec3 u_light1_dir;       // direccion hacia la fuente (direccional 1)
uniform vec3 u_light1_color;
uniform float u_light1_intensity;

uniform vec3 u_light2_dir;       // direccion hacia la fuente (direccional 2)
uniform vec3 u_light2_color;
uniform float u_light2_intensity;

uniform vec3 u_light3_pos;       // posicion de la luz puntual (emision al impactar)
uniform vec3 u_light3_color;
uniform float u_light3_intensity;

uniform vec3 u_ambient_color;    // color de la luz ambiental global

// Material del objeto
uniform vec3 u_mat_ambient;
uniform vec3 u_mat_diffuse;
uniform vec3 u_mat_specular;
uniform float u_mat_shininess;

// Textura (opcional)
uniform int u_use_texture;       // 0 o 1
uniform sampler2D u_texture;

// Posicion de la camara en el mundo (para calcular la vista en Phong)
uniform vec3 u_camera_pos;

out vec4 frag_color;

// Modelo de Phong para una fuente de luz puntual o direccional.
// L debe venir apuntando desde la superficie hacia la luz.
vec3 phong(vec3 N, vec3 V, vec3 L, vec3 lightColor, vec3 baseColor,
           vec3 specColor, float shininess, float intensity, float attenuation) {
    float NdotL = max(dot(N, L), 0.0);
    vec3 diffuse = baseColor * lightColor * NdotL;
    // Componente especular (Phong) usando el vector reflejado.
    vec3 R = reflect(-L, N);
    float spec = pow(max(dot(V, R), 0.0), shininess);
    vec3 specular = specColor * lightColor * spec;
    return (diffuse + specular) * intensity * attenuation;
}

void main() {
    vec3 N = normalize(v_world_normal);
    vec3 V = normalize(u_camera_pos - v_world_pos);

    // Color base: color del vertice multiplicado por la textura si existe.
    vec3 baseColor = v_color;
    if (u_use_texture == 1) {
        vec3 tex = texture(u_texture, v_texcoord).rgb;
        baseColor *= tex;
    }

    // Termino ambiental: luz global reflejada por la componente ambient del material.
    vec3 ambient = u_ambient_color * u_mat_ambient * baseColor;
    vec3 result = ambient;

    // Luz 1: direccional principal (escenario)
    vec3 L1 = normalize(u_light1_dir);
    result += phong(N, V, L1, u_light1_color, baseColor, u_mat_specular,
                    u_mat_shininess, u_light1_intensity, 1.0);

    // Luz 2: direccional de color (segunda fuente decorativa)
    vec3 L2 = normalize(u_light2_dir);
    result += phong(N, V, L2, u_light2_color, baseColor, u_mat_specular,
                    u_mat_shininess, u_light2_intensity, 1.0);

    // Luz 3: luz puntual "emisiva" que se prende cuando la pelota
    // golpea un bumper/slingshot/target. Se atena con la distancia.
    if (u_light3_intensity > 0.0) {
        vec3 toL = u_light3_pos - v_world_pos;
        float dist = length(toL);
        vec3 L3 = toL / max(dist, 0.0001);
        float att = 1.0 / (1.0 + 0.25 * dist + 0.06 * dist * dist);
        result += phong(N, V, L3, u_light3_color, baseColor, u_mat_specular,
                        u_mat_shininess, u_light3_intensity, att);
    }

    frag_color = vec4(result, 1.0);
}

